// Parse: enroll <phone> <name> <company> <campaignId>
// Example: enroll 919876543210 Priya Sharma Acme Corp CAMP-001
const text = ($json.text || '').trim();
const senderPhone = $json.waId || $json.from;
const senderName  = $json.senderName || 'Rep';

const parts = text.replace(/^enroll\s+/i,'').trim().split(' ');
if (parts.length < 4) {
  return [{ json: {
    senderPhone, senderName, valid: false,
    errMsg: `⚠️ Invalid format. Use:\n*enroll <phone> <name> <company> <campaignId>*\nExample: *enroll 919876543210 Priya Acme CAMP-001*`
  }}];
}

const contactPhone = parts[0];
const campaignId   = parts[parts.length - 1];
const company      = parts.slice(2, parts.length - 1).join(' ') || 'Unknown';
const contactName  = parts[1];

// Assign A/B variant randomly
const variant = Math.random() < 0.5 ? 'A' : 'B';

const now = new Date();
const tomorrow = new Date(now); tomorrow.setDate(tomorrow.getDate() + 1);

return [{ json: {
  senderPhone, senderName, valid: true,
  contactPhone, contactName, company, campaignId, variant,
  enrolledAt:    now.toISOString(),
  nextFollowUp:  tomorrow.toISOString().split('T')[0],
  confirmMsg: `✅ *Contact Enrolled!*\n\n👤 *${contactName}* (${company})\n📞 ${contactPhone}\n🎯 Campaign: ${campaignId}\n🔀 Variant: ${variant}\n\n📅 First follow-up: tomorrow`
}}];

const text  = ($json.text || '').trim();
const phone = text.replace(/^pause\s+/i,'').trim();
const senderPhone = $json.waId || $json.from;
return [{ json: { phone, senderPhone, msg: `⏸️ Contact *${phone}* has been paused.\nThey will no longer receive follow-ups until resumed.` } }];

// Filter contacts where nextFollowUp <= today AND status = Active
const allRows = $input.all();
const today   = new Date().toISOString().split('T')[0];

const due = allRows.filter(r => {
  const s = (r.json.status || '').toLowerCase();
  const d = r.json.nextFollowUp || '';
  return s === 'active' && d <= today;
});

if (due.length === 0) return [{ json: { message: 'No follow-ups due today', count: 0 } }];

return due.map(r => ({ json: {
  recordId:      r.json.id,
  contactId:     r.json.id,
  phone:         r.json.phone,
  name:          r.json.name,
  company:       r.json.company,
  campaignId:    r.json.campaignId,
  variant:       r.json.variant || 'A',
  followUpCount: parseInt(r.json.followUpCount || 0),
  stepNumber:    parseInt(r.json.followUpCount || 0) + 1,
  lastFollowUp:  r.json.lastFollowUp || null
}}));

// Build the FollowUps log row + compute next follow-up date
const contact  = $('Filter Due Follow-ups').item.json;
const msgRaw   = $json?.choices?.[0]?.message?.content || '';
const message  = msgRaw.trim();
const now      = new Date();

// Compute next follow-up: 3 days from today (adjust per campaign intervalDays if available)
const allCampaigns = $('Airtable – Read Campaign').all ? $('Airtable – Read Campaign').all() : [];
const campaign = allCampaigns.find(r => r.json.campaignId === contact.campaignId);
const intervalDays = parseInt(campaign?.json?.intervalDays || 3);

const nextDate = new Date(now);
nextDate.setDate(nextDate.getDate() + intervalDays);

const followUpId = `FU-${contact.phone}-${now.getTime()}`;

return [{ json: {
  followUpId,
  contactId:    contact.contactId,
  recordId:     contact.recordId,
  phone:        contact.phone,
  name:         contact.name,
  campaignId:   contact.campaignId,
  variant:      contact.variant,
  stepNumber:   contact.stepNumber,
  messageText:  message,
  sentAt:       now.toISOString(),
  nextFollowUp: nextDate.toISOString().split('T')[0],
  newCount:     contact.followUpCount + 1
}}];

// Find the matching contact record for the inbound phone number
const inboundPhone = $('Wati Trigger').item.json.waId || $('Wati Trigger').item.json.from;
const allRows = $input.all();
const match = allRows.find(r => (r.json.phone||'').replace(/\D/g,'') === inboundPhone.replace(/\D/g,''));

if (!match) {
  return [{ json: { found: false, inboundPhone, replyText: $('Wati Trigger').item.json.text } }];
}
return [{ json: {
  found:       true,
  inboundPhone,
  recordId:    match.json.id,
  contactId:   match.json.id,
  name:        match.json.name,
  company:     match.json.company,
  campaignId:  match.json.campaignId,
  variant:     match.json.variant,
  replyText:   $('Wati Trigger').item.json.text
}}];

const intent = ($json?.choices?.[0]?.message?.content || 'other').trim().toLowerCase();
const contact = $('Find Contact Record').item.json;
const now = new Date();

const intentEmoji = {
  interested:     '👀 Interested!',
  not_interested: '🙏 Not Interested',
  question:       '❓ Has a Question',
  converted:      '🎉 CONVERTED!',
  unsubscribe:    '🚫 Unsubscribed',
  other:          '💬 Other'
}[intent] || '💬 Other';

// Build response message based on intent
const responseMap = {
  interested:     `😊 Great to hear, *${contact.name}!* We'll be in touch very soon with more details. Is there anything specific you'd like to know?`,
  not_interested: `No worries at all, *${contact.name}!* We appreciate your time. Feel free to reach out anytime if things change. Wishing you all the best! 👋`,
  question:       `Thanks for reaching out, *${contact.name}!* We'll get someone from our team to answer your question as soon as possible. 🙌`,
  converted:      `🎉 Wonderful, *${contact.name}!* We're so excited to work with you and *${contact.company}*. Our team will contact you shortly to get started!`,
  unsubscribe:    `Understood, *${contact.name}.* We've removed you from our follow-up list. No more messages from us! Take care. 👋`,
  other:          `Thanks for your message, *${contact.name}!* Our team will review and get back to you shortly.`
};

// New contact status based on intent
const newStatus = { converted: 'Converted', unsubscribe: 'Unsubscribed', not_interested: 'Paused' }[intent] || null;

return [{ json: {
  inboundPhone:  contact.inboundPhone,
  recordId:      contact.recordId,
  contactId:     contact.contactId,
  campaignId:    contact.campaignId,
  variant:       contact.variant,
  replyText:     contact.replyText,
  intent,
  intentEmoji,
  repliedAt:     now.toISOString(),
  responseMsg:   responseMap[intent],
  newStatus,
  shouldUpdate:  !!newStatus
}}];

// Build A/B analytics + campaign dashboard
// Reads from both FollowUps and Engagement tables

const requesterPhone = $('Wati Trigger').item.json.waId || $('Wati Trigger').item.json.from;
const requesterName  = $('Wati Trigger').item.json.senderName || 'User';

const followUps  = $('Airtable – Read All Follow-ups').all().map(r => r.json);
const engagement = $('Airtable – Read All Engagement').all().map(r => r.json);

const now = new Date();

// ── Overall stats ─────────────────────────────────────────────────────
const totalSent    = followUps.length;
const totalReplies = engagement.length;
const converted    = engagement.filter(e => e.intent === 'converted').length;
const unsubscribed = engagement.filter(e => e.intent === 'unsubscribe').length;
const replyRate    = totalSent > 0 ? ((totalReplies / totalSent) * 100).toFixed(1) : '0.0';
const convRate     = totalSent > 0 ? ((converted    / totalSent) * 100).toFixed(1) : '0.0';

// ── A/B breakdown ─────────────────────────────────────────────────────
const sentA = followUps.filter(f => f.variant === 'A').length;
const sentB = followUps.filter(f => f.variant === 'B').length;
const replA = engagement.filter(e => e.variant === 'A').length;
const replB = engagement.filter(e => e.variant === 'B').length;
const convA = engagement.filter(e => e.variant === 'A' && e.intent === 'converted').length;
const convB = engagement.filter(e => e.variant === 'B' && e.intent === 'converted').length;
const rrA   = sentA > 0 ? ((replA / sentA) * 100).toFixed(1) : '0.0';
const rrB   = sentB > 0 ? ((replB / sentB) * 100).toFixed(1) : '0.0';
const crA   = sentA > 0 ? ((convA / sentA) * 100).toFixed(1) : '0.0';
const crB   = sentB > 0 ? ((convB / sentB) * 100).toFixed(1) : '0.0';
const winner = parseFloat(crA) >= parseFloat(crB) ? '🏆 Variant A wins on conversion' : '🏆 Variant B wins on conversion';

// ── Per-campaign stats ────────────────────────────────────────────────
const byCampaign = {};
for (const f of followUps) {
  const c = f.campaignId || 'Unknown';
  if (!byCampaign[c]) byCampaign[c] = { sent:0, replies:0, conversions:0 };
  byCampaign[c].sent++;
}
for (const e of engagement) {
  const c = e.campaignId || 'Unknown';
  if (!byCampaign[c]) byCampaign[c] = { sent:0, replies:0, conversions:0 };
  byCampaign[c].replies++;
  if (e.intent === 'converted') byCampaign[c].conversions++;
}

const campLines = Object.entries(byCampaign).map(([id, s]) => {
  const rr = s.sent > 0 ? ((s.replies/s.sent)*100).toFixed(0) : 0;
  return `  📁 *${id}* — Sent: ${s.sent} | Replies: ${s.replies} (${rr}%) | Conv: ${s.conversions}`;
});

// ── Recent replies ────────────────────────────────────────────────────
const intentEmoji = { interested:'👀',not_interested:'🙏',question:'❓',converted:'🎉',unsubscribe:'🚫',other:'💬' };
const recentReplies = engagement
  .sort((a,b) => new Date(b.repliedAt) - new Date(a.repliedAt))
  .slice(0,5)
  .map(e => {
    const dt = e.repliedAt ? new Date(e.repliedAt).toLocaleDateString('en-IN',{day:'numeric',month:'short',hour:'2-digit',minute:'2-digit'}) : '';
    return `  ${intentEmoji[e.intent]||'💬'} ${e.phone} — ${e.intent} (${dt})`;
  });

// ── Build message ─────────────────────────────────────────────────────
const lines = [
  `📊 *Follow-up Campaign Analytics*`,
  `👤 ${requesterName} · ${now.toLocaleDateString('en-IN',{day:'numeric',month:'short',year:'numeric'})}`,
  '',
  `━━ *Overall Performance* ━━`,
  `📤 Total Sent:      *${totalSent}*`,
  `💬 Total Replies:   *${totalReplies}* (${replyRate}%)`,
  `🎉 Conversions:    *${converted}* (${convRate}%)`,
  `🚫 Unsubscribed:   *${unsubscribed}*`,
  '',
  `━━ *A/B Test Results* ━━`,
  `🅰️ Variant A — Sent: ${sentA} | Reply: ${rrA}% | Conv: ${crA}%`,
  `🅱️ Variant B — Sent: ${sentB} | Reply: ${rrB}% | Conv: ${crB}%`,
  winner,
  '',
  `━━ *By Campaign* ━━`,
  ...campLines,
  '',
  `━━ *Recent Replies* ━━`,
  ...recentReplies,
  '',
  'Reply *enroll* to add a contact — *pause* to pause one.'
];

return [{ json: { requesterPhone, report: lines.join('\n') } }];
